module fixed_point_multiplier(  
    input [15:0] a,  
    input [15:0] b,  
    output [15:0] result  
);  
  wire [15:0] _tap_a = a & {16{1'b1}};

    wire [31:0] product;  
    assign product = a * b;  
    assign result = product[23:8]; // Shift right to adjust the fixed-point format  
endmodule
